#!/usr/bin/env python3
"""
gkq_gpu_proof.py (ADDITIVE)

Strong nvidia-smi proof: upload one real layer's quantized data to the GPU
ONCE, then launch the reconstruct_weights_spectral kernel back-to-back many
times (no per-iteration H2D/D2H, no Python marshalling between launches), so
GPU utilization pins high and is unambiguous in nvidia-smi.

Uses the SAME NVRTC-compiled sm_61 module as gkq_gpu_binding.
"""
import os, sys, time, ctypes, importlib.util
import numpy as np

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, HERE)
import gkq_gpu_binding as gpu

# load a real layer from llama-gkq.knot via the unmodified server loader
spec = importlib.util.spec_from_file_location(
    "inference_server_gkq", os.path.join(HERE, "inference-server-gkq.py"))
srv = importlib.util.module_from_spec(spec); spec.loader.exec_module(srv)

knot = os.getenv("WEIGHTS_PATH", os.path.join(HERE, "rknots", "llama-gkq.knot"))
c = srv.MemoryResidentWeightCache(weights_path=knot, gpu_cache_size_mb=2000)
c.load_quantized_weights()
key = "layer_1"  # 28672 x 8192 -> big kernel
q, m = c.quantized_weights[key], c.metadata[key]
d_out, d_in = int(m["d_out"]), int(m["d_in"])
u_max, sigma_max, v_max = float(m["U_max"]), float(m["sigma_max"]), float(m["V_max"])
U_min = -128.0/127.0*u_max; V_min = -128.0/127.0*v_max

rec = gpu.get_reconstructor()
cuda = gpu.cuda

U = np.ascontiguousarray(q["U_q8"], np.uint8)
S = np.ascontiguousarray(q["sigma_q8"], np.uint8)
V = np.ascontiguousarray(q["V_q8"], np.uint8)
Wn = d_out * d_in * 4

dU=ctypes.c_void_p(); dS=ctypes.c_void_p(); dV=ctypes.c_void_p(); dW=ctypes.c_void_p()
gpu._chk(cuda.cuMemAlloc_v2(ctypes.byref(dU), U.nbytes), "U")
gpu._chk(cuda.cuMemAlloc_v2(ctypes.byref(dS), S.nbytes), "S")
gpu._chk(cuda.cuMemAlloc_v2(ctypes.byref(dV), V.nbytes), "V")
gpu._chk(cuda.cuMemAlloc_v2(ctypes.byref(dW), Wn), "W")
gpu._chk(cuda.cuMemcpyHtoD_v2(dU, U.ctypes.data_as(ctypes.c_void_p), U.nbytes), "U")
gpu._chk(cuda.cuMemcpyHtoD_v2(dS, S.ctypes.data_as(ctypes.c_void_p), S.nbytes), "S")
gpu._chk(cuda.cuMemcpyHtoD_v2(dV, V.ctypes.data_as(ctypes.c_void_p), V.nbytes), "V")

c_do=ctypes.c_int(d_out); c_di=ctypes.c_int(d_in)
fU0,fU1=ctypes.c_float(U_min),ctypes.c_float(u_max)
fS0,fS1=ctypes.c_float(0.0),ctypes.c_float(sigma_max)
fV0,fV1=ctypes.c_float(V_min),ctypes.c_float(v_max)
args=[dU,dS,dV,dW,c_do,c_di,fU0,fU1,fS0,fS1,fV0,fV1]
argp=(ctypes.c_void_p*len(args))(*[ctypes.cast(ctypes.byref(a),ctypes.c_void_p) for a in args])
B=16; gx=(d_in+B-1)//B; gy=(d_out+B-1)//B

secs = int(sys.argv[1]) if len(sys.argv) > 1 else 30
print(f"layer {key} {d_out}x{d_in}, launching kernel back-to-back for ~{secs}s")
t0=time.time(); n=0
while time.time()-t0 < secs:
    for _ in range(200):
        gpu._chk(cuda.cuLaunchKernel(rec.func, gx,gy,1, B,B,1, 0,None, argp,None),"launch")
        n+=1
    gpu._chk(cuda.cuCtxSynchronize(),"sync")
print(f"done: {n} kernel launches in {time.time()-t0:.1f}s ({n/(time.time()-t0):.0f} launches/s)")
